1	/**
2	 * T8: Container-start workspace pull with fail-fast validation
3	 * and skill_reference_audit event.
4	 *
5	 * Every container start performs three things:
6	 *   1. Load and validate agent.yaml via T2's validator — fail-fast on invalid config.
7	 *   2. Clone or pull each watched workspace and the workflow repo.
8	 *   3. Audit skill references across all tasks.md files — informational, non-fatal.
9	 *
10	 * Clone-vs-pull logic:
11	 *   - Local path missing or not a git repo  → git clone
12	 *   - Local path present and is a git repo  → git fetch + git reset --hard origin/<base>
13	 *
14	 * Exit codes:
15	 *   0  success
16	 *   2  agent.yaml validation failed
17	 *   3  git clone / pull failed
18	 *   4  unexpected bootstrap error
19	 */
20	
21	import { execSync } from "node:child_process";
22	import { existsSync, readdirSync, mkdirSync, readFileSync } from "node:fs";
23	import { join } from "node:path";
24	import { parse as parseYaml } from "yaml";
25	import { loadAgentYaml, type AgentConfig } from "../config/validate-agent-yaml.js";
26	import { parseTasksMd } from "../eligibility/parse-tasks-md.js";
27	import { buildGitEnv } from "../git-env.js";
28	
29	// ── Exit codes ────────────────────────────────────────────────────────────────
30	
31	export const EXIT_SUCCESS = 0 as const;
32	export const EXIT_VALIDATION_FAILED = 2 as const;
33	export const EXIT_GIT_FAILED = 3 as const;
34	export const EXIT_UNEXPECTED = 4 as const;
35	
36	export type ExitCode = 0 | 2 | 3 | 4;
37	
38	// ── Bootstrap event types ─────────────────────────────────────────────────────
39	
40	export interface BootstrapStartedEvent {
41	  type: "bootstrap_started";
42	  agent_yaml_path: string;
43	  watches: string[];
44	  at: string;
45	}
46	
47	export interface WorkspaceClonedEvent {
48	  type: "workspace_cloned";
49	  workspace_url: string;
50	  local_path: string;
51	  at: string;
52	}
53	
54	export interface WorkspacePulledEvent {
55	  type: "workspace_pulled";
56	  workspace_url: string;
57	  local_path: string;
58	  at: string;
59	}
60	
61	export interface BootstrapFailedEvent {
62	  type: "bootstrap_failed";
63	  reason: string;
64	  details: string;
65	  at: string;
66	}
67	
68	export interface SkillReferenceAuditEvent {
69	  type: "skill_reference_audit";
70	  workspace_id: string;
71	  feature_id: string;
72	  task_id: string;
73	  missing_slug: string;
74	  at: string;
75	}
76	
77	export interface BootstrapReadyEvent {
78	  type: "bootstrap_ready";
79	  at: string;
80	}
81	
82	export type BootstrapEvent =
83	  | BootstrapStartedEvent
84	  | WorkspaceClonedEvent
85	  | WorkspacePulledEvent
86	  | BootstrapFailedEvent
87	  | SkillReferenceAuditEvent
88	  | BootstrapReadyEvent;
89	
90	// ── Public options ────────────────────────────────────────────────────────────
91	
92	export interface BootstrapOptions {
93	  /** Absolute path to the agent.yaml file to validate. */
94	  agentYamlPath: string;
95	  /**
96	   * Absolute local path to the workflow repo (contains technical_skills/).
97	   * If the path doesn't exist and workflowUrl is provided, the repo is cloned here.
98	   */
99	  workflowLocalPath: string;
100	  /** SSH URL of the workflow repo — required if workflowLocalPath doesn't exist yet. */
101	  workflowUrl?: string;
102	  /** Base branch for the workflow repo. Default: "main". */
103	  workflowBaseBranch?: string;
104	  /**
105	   * Root directory under which watched workspaces are cloned.
106	   * Derived local path: <workspacesRoot>/<repo-name-from-ssh-url>
107	   * (e.g. git@github.com:org/project.git → <workspacesRoot>/project)
108	   */
109	  workspacesRoot: string;
110	  /**
111	   * Explicit SSH-URL → local-path overrides.
112	   * When a URL is present here, it takes precedence over the auto-derived path.
113	   * Intended for tests and for container environments that pre-mount repos.
114	   */
115	  workspaceLocalPaths?: Map<string, string>;
116	  /** Base branch for every watched workspace. Default: "main". */
117	  workspaceBaseBranch?: string;
118	  /** SSH private key path for all git operations. */
119	  sshKeyPath?: string;
120	  /**
121	   * Override the event emitter (default: write JSON to stdout via console.log).
122	   * Inject a no-op or recording emitter in tests.
123	   */
124	  emit?: (event: BootstrapEvent) => void;
125	  /**
126	   * Skip all real git operations (clone / fetch / reset).
127	   * The filesystem is still inspected for the skill audit.
128	   * Intended for unit tests that seed the filesystem directly.
129	   */
130	  skipGit?: boolean;
131	}
132	
133	export interface BootstrapResult {
134	  exitCode: ExitCode;
135	  /** Parsed and validated agent config — present only on exit code 0. */
136	  config?: AgentConfig;
137	}
138	
139	// ── Internal helpers ──────────────────────────────────────────────────────────
140	
141	function defaultEmit(event: BootstrapEvent): void {
142	  console.log(JSON.stringify(event));
143	}
144	
145	export { buildGitEnv };
146	
147	/** Return true if localPath contains a .git directory. */
148	function isGitRepo(localPath: string): boolean {
149	  return existsSync(localPath) && existsSync(join(localPath, ".git"));
150	}
151	
152	/**
153	 * Extract the repository name from an SSH or HTTPS URL.
154	 *   git@github.com:org/repo-name.git  →  repo-name
155	 *   https://github.com/org/repo.git   →  repo
156	 */
157	function extractRepoName(url: string): string {
158	  const match = /\/([^/]+?)(?:\.git)?$/.exec(url);
159	  return match?.[1] ?? url;
160	}
161	
162	/** Resolve the local filesystem path for a watched workspace URL. */
163	function resolveLocalPath(
164	  watchUrl: string,
165	  workspacesRoot: string,
166	  overrides: Map<string, string> | undefined,
167	): string {
168	  if (overrides?.has(watchUrl)) {
169	    return overrides.get(watchUrl)!;
170	  }
171	  return join(workspacesRoot, extractRepoName(watchUrl));
172	}
173	
174	/**
175	 * Clone or pull a single git repository.
176	 * - Already a git repo  → fetch + reset --hard to origin/<baseBranch>.
177	 * - Directory absent (or empty)  → mkdirSync + git clone.
178	 * Returns "cloned" | "pulled".
179	 */
180	export function syncRepo(
181	  url: string,
182	  localPath: string,
183	  baseBranch: string,
184	  gitEnv: NodeJS.ProcessEnv,
185	): "cloned" | "pulled" {
186	  if (isGitRepo(localPath)) {
187	    execSync(`git -C "${localPath}" fetch origin`, { env: gitEnv, stdio: "pipe" });
188	    execSync(
189	      `git -C "${localPath}" reset --hard "origin/${baseBranch}"`,
190	      { env: gitEnv, stdio: "pipe" },
191	    );
192	    return "pulled";
193	  }
194	
195	  mkdirSync(localPath, { recursive: true });
196	  execSync(`git clone "${url}" "${localPath}"`, { env: gitEnv, stdio: "pipe" });
197	  return "cloned";
198	}
199	
200	/**
201	 * Return the set of skill slugs that exist as directories under
202	 * <workflowLocalPath>/technical_skills/. An absent or unreadable directory
203	 * returns an empty set (causing all referenced slugs to be flagged).
204	 */
205	function loadExistingSkills(workflowLocalPath: string): Set<string> {
206	  const skillsRoot = join(workflowLocalPath, "technical_skills");
207	  if (!existsSync(skillsRoot)) return new Set();
208	  try {
209	    return new Set(readdirSync(skillsRoot));
210	  } catch {
211	    return new Set();
212	  }
213	}
214	
215	/**
216	 * Enumerate every tasks.md under <workspaceLocalPath>/docs/features/<featureId>/
217	 * and return an iterable of { featureId, content } pairs.
218	 */
219	function* findTasksMd(
220	  workspaceLocalPath: string,
221	): Generator<{ featureId: string; content: string }> {
222	  const featuresRoot = join(workspaceLocalPath, "docs", "features");
223	  if (!existsSync(featuresRoot)) return;
224	
225	  let entries: string[];
226	  try {
227	    entries = readdirSync(featuresRoot);
228	  } catch {
229	    return;
230	  }
231	
232	  for (const featureId of entries) {
233	    const tasksMdPath = join(featuresRoot, featureId, "tasks.md");
234	    if (!existsSync(tasksMdPath)) continue;
235	    try {
236	      const content = readFileSync(tasksMdPath, "utf-8");
237	      yield { featureId, content };
238	    } catch {
239	      // Unreadable file — skip silently.
240	    }
241	  }
242	}
243	
244	// ── Public API ────────────────────────────────────────────────────────────────
245	
246	/**
247	 * Run the container-start bootstrap sequence.
248	 *
249	 * @returns A BootstrapResult whose exitCode maps to the process exit code.
250	 *          The caller is responsible for calling process.exit(result.exitCode).
251	 */
252	export async function runBootstrap(opts: BootstrapOptions): Promise<BootstrapResult> {
253	  const {
254	    agentYamlPath,
255	    workflowLocalPath,
256	    workflowUrl,
257	    workflowBaseBranch = "main",
258	    workspacesRoot,
259	    workspaceLocalPaths,
260	    workspaceBaseBranch = "main",
261	    sshKeyPath,
262	    emit = defaultEmit,
263	    skipGit = false,
264	  } = opts;
265	
266	  try {
267	    // ── 1. Load and validate agent.yaml ──────────────────────────────────────
268	    let validationResult;
269	    try {
270	      validationResult = loadAgentYaml(agentYamlPath);
271	    } catch (e) {
272	      emit({
273	        type: "bootstrap_failed",
274	        reason: "agent_yaml_unreadable",
275	        details: `Cannot read ${agentYamlPath}: ${(e as Error).message}`,
276	        at: new Date().toISOString(),
277	      });
278	      return { exitCode: EXIT_VALIDATION_FAILED };
279	    }
280	
281	    if (!validationResult.valid) {
282	      const details = validationResult.errors
283	        .map((e) => `${e.path}: ${e.message}`)
284	        .join("; ");
285	      emit({
286	        type: "bootstrap_failed",
287	        reason: "agent_yaml_invalid",
288	        details,
289	        at: new Date().toISOString(),
290	      });
291	      return { exitCode: EXIT_VALIDATION_FAILED };
292	    }
293	
294	    const config = validationResult.config;
295	
296	    // ── 2. Kill switch ────────────────────────────────────────────────────────
297	    if (!config.enabled) {
298	      emit({ type: "bootstrap_ready", at: new Date().toISOString() });
299	      return { exitCode: EXIT_SUCCESS, config };
300	    }
301	
302	    // ── 3. Emit bootstrap_started ─────────────────────────────────────────────
303	    emit({
304	      type: "bootstrap_started",
305	      agent_yaml_path: agentYamlPath,
306	      watches: config.watches,
307	      at: new Date().toISOString(),
308	    });
309	
310	    const gitEnv = buildGitEnv(sshKeyPath);
311	
312	    // ── 4. Clone or pull the workflow repo ────────────────────────────────────
313	    if (!skipGit && workflowUrl) {
314	      try {
315	        const action = syncRepo(workflowUrl, workflowLocalPath, workflowBaseBranch, gitEnv);
316	        emit({
317	          type: action === "cloned" ? "workspace_cloned" : "workspace_pulled",
318	          workspace_url: workflowUrl,
319	          local_path: workflowLocalPath,
320	          at: new Date().toISOString(),
321	        });
322	      } catch (e) {
323	        emit({
324	          type: "bootstrap_failed",
325	          reason: "git_workflow_sync_failed",
326	          details: `Failed to sync workflow repo ${workflowUrl}: ${(e as Error).message}`,
327	          at: new Date().toISOString(),
328	        });
329	        return { exitCode: EXIT_GIT_FAILED };
330	      }
331	    }
332	
333	    // ── 5. Clone or pull each watched workspace ───────────────────────────────
334	    for (const watchUrl of config.watches) {
335	      const localPath = resolveLocalPath(watchUrl, workspacesRoot, workspaceLocalPaths);
336	
337	      if (!skipGit) {
338	        try {
339	          const action = syncRepo(watchUrl, localPath, workspaceBaseBranch, gitEnv);
340	          emit({
341	            type: action === "cloned" ? "workspace_cloned" : "workspace_pulled",
342	            workspace_url: watchUrl,
343	            local_path: localPath,
344	            at: new Date().toISOString(),
345	          });
346	        } catch (e) {
347	          emit({
348	            type: "bootstrap_failed",
349	            reason: "git_workspace_sync_failed",
350	            details: `Failed to sync workspace ${watchUrl}: ${(e as Error).message}`,
351	            at: new Date().toISOString(),
352	          });
353	          return { exitCode: EXIT_GIT_FAILED };
354	        }
355	      }
356	    }
357	
358	    // ── 5b. Clone / pull implementation repos from workspace.yaml ────────────
359	    // For each watched management workspace, read workspace.yaml and clone every
360	    // repo that is NOT itself a management repo (i.e. not already in watches[]).
361	    // Also sets process.env[VAR] for every local_path: env:<VAR> declaration so
362	    // that resolveRepoLocalPath in main.ts can do a simple env-var lookup.
363	    //
364	    // Non-fatal if workspace.yaml is absent or has no repos[] — management-only
365	    // workspaces are valid.
366	    {
367	      type WorkspaceRepoEntry = {
368	        id: string;
369	        github: string;
370	        local_path?: string;
371	        base_branch?: string;
372	      };
373	
374	      const watchUrlSet = new Set(config.watches);
375	
376	      for (const watchUrl of config.watches) {
377	        const mgmtLocalPath = resolveLocalPath(watchUrl, workspacesRoot, workspaceLocalPaths);
378	        const workspaceYamlPath = join(mgmtLocalPath, "workspace.yaml");
379	
380	        if (!existsSync(workspaceYamlPath)) continue;
381	
382	        let repos: WorkspaceRepoEntry[];
383	        try {
384	          const parsed = parseYaml(readFileSync(workspaceYamlPath, "utf-8")) as {
385	            repos?: WorkspaceRepoEntry[];
386	          };
387	          repos = parsed.repos ?? [];
388	        } catch {
389	          continue; // Unreadable or malformed workspace.yaml — skip silently.
390	        }
391	
392	        for (const repo of repos) {
393	          // Skip entries with no URL (malformed workspace.yaml row).
394	          if (!repo.github) continue;
395	
396	          // Watched repos (management repo) are already git-synced in step 5.
397	          // We still need to populate their env var so resolveRepoLocalPath works.
398	          const isWatched = watchUrlSet.has(repo.github);
399	          const localPath = isWatched
400	            ? resolveLocalPath(repo.github, workspacesRoot, workspaceLocalPaths)
401	            : join(workspacesRoot, extractRepoName(repo.github));
402	
403	          if (!isWatched && !skipGit) {
404	            const branch = repo.base_branch ?? workspaceBaseBranch;
405	            try {
406	              const action = syncRepo(repo.github, localPath, branch, gitEnv);
407	              emit({
408	                type: action === "cloned" ? "workspace_cloned" : "workspace_pulled",
409	                workspace_url: repo.github,
410	                local_path: localPath,
411	                at: new Date().toISOString(),
412	              });
413	            } catch (e) {
414	              emit({
415	                type: "bootstrap_failed",
416	                reason: "git_impl_repo_sync_failed",
417	                details: `Failed to sync impl repo ${repo.github}: ${(e as Error).message}`,
418	                at: new Date().toISOString(),
419	              });
420	              return { exitCode: EXIT_GIT_FAILED };
421	            }
422	          }
423	
424	          // Populate env var so resolveRepoLocalPath can do a plain env lookup.
425	          if (repo.local_path?.startsWith("env:")) {
426	            const varName = repo.local_path.slice(4);
427	            process.env[varName] = localPath;
428	          }
429	        }
430	      }
431	    }
432	
433	    // ── 6. Skill reference audit ──────────────────────────────────────────────
434	    // Informational only — never fatal. Bootstrap continues even when slugs are missing.
